// CSS declarations for the Expo web template files. Normally provided by the
// generated expo-env.d.ts on first `expo start`; declared here so `tsc --noEmit`
// works in CI and fresh clones without running Expo first.
declare module '*.module.css' {
  const classes: { readonly [key: string]: string };
  export default classes;
}
declare module '*.css';
